var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으갸악!!!!","JPN":"うええっ！！！","ENG":"AAACK!!!","TWN":"呃啊啊啊！！！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어라? 내가 왜…….","JPN":"あれ？　何で私……","ENG":"Huh? Why am I...","TWN":"嗯？我怎麼……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"난 분명…….","JPN":"私、確か……","ENG":"I was...","TWN":"我明明……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님의 공격에 휩쓸린 뒤에…….","JPN":"アーディティヤ様の攻撃に巻き込まれて……","ENG":"After I got caught up in Miss Aditya's attack...","TWN":"受到阿迪亞的攻擊波及後……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"침식체한테…… 먹혔는데?","JPN":"侵食体に……喰われた……よね？","ENG":"I was... swallowed by the C.O.","TWN":"被侵蝕體吃掉了……不是嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아그그…… 아파라…… 상처는 그대로잖아.","JPN":"いてて……痛い……って、傷はそのままじゃん……","ENG":"Oww... Ouch... My wounds are still there.","TWN":"啊嗚嗚……好痛……傷口是真的啊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어떻게 살아있는 거지?","JPN":"どうして生きているのだろう？","ENG":"But how am I still alive?","TWN":"但我怎麼還活著？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"나침반 바늘도 방향을 잡지 못하고 있어.","JPN":"羅針盤の針も、方向が安定しなくなっている。","ENG":"The compass keeps spinning like it doesn't know which way to point.","TWN":"指南針也找不到方向。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"적어도 아디트야 님이 근처에는 없다는 소린데…….","JPN":"少なくともアーディティヤ様の近くではないってことよね……","ENG":"This means that Miss Aditya is not around here, at least...","TWN":"至少說明阿迪亞不在附近……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼 여긴 대체 어디지……?","JPN":"じゃあ、いったいここは……？","ENG":"Then, where in the world am I...?","TWN":"那這裡到底是哪裡……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래. 이제야 알겠어. 이곳은 바로…….","JPN":"そうか、わかったわ。ここは……","ENG":"Okay. Now I understand. This is...","TWN":"嗯，我知道了。這裡是……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"지옥이구나!","JPN":"地獄なんだ！","ENG":"Hell!","TWN":"地獄！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":" 으으…… 역시 지옥도 이면세계와 별반 다를 게 없었어…….","JPN":"うう……やっぱり地獄も裏世界とほとんど変わらないんだ……","ENG":"Ngh... Guess hell isn't that much different from the Counterside...","TWN":"呃呃……原來地獄和異界沒什麼兩樣啊……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야님은 무사히 살아나가셨을까?","JPN":"アーディティヤ様は無事なのかな？","ENG":"I wonder if Miss Aditya made it out okay.","TWN":"阿迪亞是不是平安無事呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시, 그냥 그 캡슐에서 깨우지 말아야 했을지도.","JPN":"あの時、カプセルから目を覚まさせない方が良かったのかもしれない。","ENG":"Maybe I shouldn't have woken her up in the capsule.","TWN":"也許不該從那個膠囊裡叫醒她。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하, 하지만 그렇게 되면 난 어디 팔려나갔을지도 몰라.","JPN":"で、でも、それじゃ、私は今頃どこかに売り飛ばされていたかもしれないし。","ENG":"B-but if I didn't, I would've been sold off to somewhere as a slave.","TWN":"但，但那樣的話，也不知道會被賣到哪裡去。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"결국 죽었는데 뭘. 결말은 똑같은 거 아니야?","JPN":"まあ、死んじゃったもんね。結末は変わらないんじゃない？","ENG":"Then again, I'm dead now. So, guess it ended the same.","TWN":"現在死都死了，結局不都是一樣的嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇지…… 어찌 되었든 이미 나는 죽을 운명이었던 거야.","JPN":"そう……結局私は死ぬ運命だったのよ。","ENG":"Right... Whatever the case, I was fated to die.","TWN":"是啊……無論如何都會死……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이런 곳에 사람 발소리가?","JPN":"こんなところに人の足音が？","ENG":"Why do I hear footsteps?","TWN":"這裡怎麼會有腳步聲？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이쯤이었던 것 같은데…… 아, 저쪽인가?","JPN":"この辺りだったはずだけど……あっ、あっちかな。","ENG":"I think they came from around here... Oh, is it that way?","TWN":"好像是這附近……啊，在那邊？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저 사람들은…….","JPN":"あの人たちは……","ENG":"Who are they...?","TWN":"這些人是……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"관리국쪽 사람 같은데…… 근데 분위기가 조금…….","JPN":"管理局の人に見えるわ……でも少し変な雰囲気……","ENG":"They look like they're from the Administration... But something feels different about them...","TWN":"看起來像是管理局的士兵……不過感覺有點……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"작전 브리핑은 모두 들었겠지? 외곽부터 빠르게 훑고 지나간다.","JPN":"作戦の説明は皆聞いているだろう？　外郭から段々狭めていくぞ。","ENG":"Did you all hear the operation briefing? We're going to quickly pass through starting from the outskirts.","TWN":"作戰簡報都聽過了吧？從周邊迅速掃蕩過去。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"작전 브리핑은 모두 들었겠지? 외곽부터 빠르게 훑고 지나간다.","JPN":"作戦の説明は皆聞いているだろう？　外郭から段々狭めていくぞ。","ENG":"Did you all hear the operation briefing? We're going to quickly pass through starting from the outskirts.","TWN":"作戰簡報都聽過了吧？從周邊迅速掃蕩過去。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ff3636>작</color>전 브리핑은</color> 모두 들<color=#ff3636>었</color>겠지? 외<color=#ff3636>곽부</color>터 <color=#ff3636>빠</color>르게 훑고 지나간다.","JPN":"<color=#ff3636>作</color>戦の説明は</color>皆<color=#ff3636>聞いて</color>いるだろう？　外<color=#ff3636>郭</color>から<color=#ff3636>段々</color>狭めていくぞ。","ENG":"<color=#ff3636>Di</color>d you</color> all hear the operation <color=#ff3636>bri</color>efing? We're going to <color=#ff3636>quick</color>ly pass through starting from the <color=#ff3636>out</color>skirts.","TWN":"<color=#ff3636>作</color>戰簡報都<color=#ff3636>聽</color>過了吧？從周<color=#ff3636>邊</color>迅速掃蕩過去。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저 사람들. 똑같은 행동을 반복하고 있어……?","JPN":"あの人たち、同じ動きを繰り返している……？","ENG":"Those people. Why are they repeating the same movements over and over again...?","TWN":"那些人，一直在重複同樣的動作……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저기요! ","JPN":"あのぉ！ ","ENG":"Excuse me?!","TWN":"喂！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"읍?!","JPN":"うっ！？","ENG":"Mmph?!","TWN":"唔？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"쉬잇. 가만히 있어요.","JPN":"しっ、静かにしてください。","ENG":"Shh! Stay still.","TWN":"噓，別動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"읍! 읍읍읍! 읍!","JPN":"うっ！　うううっ！！","ENG":"Mmff! Mmphh! MMMMPH!!","TWN":"唔！唔唔唔！唔！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"<color=#ffd34c>저것들</color>한테 말을 걸면 안 돼요.","JPN":"<color=#ffd34c>あれ</color>に声をかけてはいけません。","ENG":"You can't talk to <color=#ffd34c>them</color>.","TWN":"不能跟<color=#ffd34c>那些傢伙</color>搭話。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"당신을 인지한 순간, 저들은 당신을 공격할 거예요.","JPN":"あなたを認知した瞬間、彼らは攻撃してきます。","ENG":"The second they notice you, they will start attacking you.","TWN":"一旦讓他們察覺到你，就會受到攻擊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"제가 입을 풀어드릴 테니 가만히 있으셔야 해요?","JPN":"手を離しますから、大人しくしてくださいね？","ENG":"I'm going to take my hand off your mouth, so could you stay calm?","TWN":"我慢慢鬆開手，你不許大喊大叫喔？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"당신은…… 사막에서 우릴 습격했던 그림자?","JPN":"あなたは……砂漠で私たちを襲ってきたシャドウ？","ENG":"You're... the Shadow who attacked us at the desert?","TWN":"你是……在沙漠裡攻擊我們的暗影？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"네? 그, 그림자요?! 전 여기서 당신을 처음 보는데요?!","JPN":"はい？　しゃ、シャドウ！？　私はあなたとはここで初めて会いましたよ！？","ENG":"What? A Shadow?! This is the first time I'm seeing you!","TWN":"什麼？暗影？！我是第一次見到你欸！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"모르는 척하지 마세요! 당신 때문에 죽을 뻔했다고요!","JPN":"とぼけないでください！　私はあなたに殺されかけたんですから！","ENG":"Don't play dumb! You almost kill me, you know!","TWN":"別裝傻了！我差點就死在你手裡欸！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"애초에 그림자와 이렇게 평화롭게 대화를 나눌 수 있을 리가 없잖아요…….","JPN":"もしシャドウなら、こんなふうに普通に会話するなんて、あり得ないじゃないですか……","ENG":"There's no way you can have a peaceful talk with a Shadow in the first place...","TWN":"如果我是暗影的話，不可能這麼和平地跟你對話吧……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그건 모르는 거죠. 맹수도 사냥감을 잡을 땐 조용히 접근하는걸요.","JPN":"そうとも言い切れませんね。猛獣も獲物を狙うときは、こっそり近づくもんですから。","ENG":"You don't know that. Even wild animals approach quietly when hunting prey.","TWN":"不好說，猛獸在捕獵時也是悄悄接近獵物的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"당신이 절 잡아먹으려고 인간인 척하는 그림자일지도 모르잖아요?","JPN":"あなたもそんなふうに、人間のふりをして近づいてきたシャドウかもしれませんもの！","ENG":"You might be a Shadow who's pretending to be human so you can eat me!","TWN":"誰知道你是不是偽裝成人類，然後打算一口吃掉我？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"여기가 지옥이라고 말하신 분 치고는 굉장히 조심스러운 반응이네요.","JPN":"ここが地獄だと言っていたわりには、自分の身を案じるようなことを言うんですね。","ENG":"For someone who called this place hell, you're awfully careful.","TWN":"還說這裡是地獄，反應卻相當謹慎呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그, 그건 언제부터 엿듣고 있었던 거예요?! 여기가 지옥이 아니라는 말인가요?","JPN":"ぜ、全部聞いていたんですか！？　ここって、地獄じゃないんですか？","ENG":"W-were you eavesdropping on me this whole time?! Wait, you're saying that this isn't hell?","TWN":"你，你偷聽我說話？！所以這裡不是地獄嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 소리는……?","JPN":"この音は……？","ENG":"What's that sound...?","TWN":"這聲音是……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하. 일단 지옥은 아니라고 말씀드릴게요. ","JPN":"あはは。地獄じゃないってことだけは言っておきます。 ","ENG":"Ah hah hah. No, this isn't hell.","TWN":"呵呵呵，總之這裡不是地獄。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"일단 저 사람들 눈을 피하는 게 우선이겠어요.","JPN":"とりあえず、あの人たちに見つからないようにここを離れましょう。","ENG":"And we should make sure not to be seen by them first.","TWN":"我們得避開那些人的視線。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"절 믿는 건 자유지만, 따라오는 걸 권장하고 싶네요.","JPN":"私を信じるかどうかは自由ですが、私について来た方がいいですよ。","ENG":"It's your choice to trust me, but I recommend that you follow me.","TWN":"信不信由你，但我建議你還是跟上來吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"제가 아는 분과 많이 닮으셔서, 꼭 도와드리고 싶거든요.\xA0","JPN":"私の知っている方によく似ているので、あなたを助けたいんです。\xA0","ENG":"You look similar to someone I know, so I want to help.\xA0","TWN":"因為你很像我認識的一個人，所以我才想幫你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아는 분…… 이라고요?","JPN":"知っている方……？","ENG":"Someone... you know?","TWN":"認識的人……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"}]`);export{e as default};